## Session 5: Forms & Validation

Forms are how users interact with applications. Accessible, usable, and validated forms require careful attention to HTML semantics, CSS, and JavaScript.

### Semantic Form Structure

```html
<form id="registration" novalidate aria-label="Create account">
  <!-- Always associate labels with inputs -->
  <div class="field">
    <label for="email">Email address <span aria-hidden="true">*</span></label>
    <input
      id="email"
      type="email"
      name="email"
      autocomplete="email"
      required
      aria-required="true"
      aria-describedby="email-hint email-error"
      placeholder="you@example.com"
    >
    <p id="email-hint" class="hint">We'll never share your email.</p>
    <p id="email-error" class="error" role="alert" aria-live="polite" hidden></p>
  </div>

  <div class="field">
    <label for="password">Password</label>
    <input
      id="password"
      type="password"
      name="password"
      required
      minlength="8"
      autocomplete="new-password"
      aria-describedby="password-requirements"
    >
    <ul id="password-requirements">
      <li>At least 8 characters</li>
      <li>One uppercase letter</li>
    </ul>
  </div>

  <!-- Fieldset for grouped inputs -->
  <fieldset>
    <legend>Preferred contact method</legend>
    <label><input type="radio" name="contact" value="email"> Email</label>
    <label><input type="radio" name="contact" value="phone"> Phone</label>
  </fieldset>

  <button type="submit">Create account</button>
</form>
```

### HTML5 Input Types

```html
<input type="text">        <!-- default -->
<input type="email">       <!-- email keyboard on mobile, basic validation -->
<input type="password">    <!-- masked, disable autocomplete appropriately -->
<input type="number">      <!-- numeric keyboard, min/max/step attributes -->
<input type="tel">         <!-- phone keyboard on mobile -->
<input type="url">         -- URL validation --
<input type="date">        <!-- date picker -->
<input type="datetime-local"> <!-- date + time -->
<input type="color">       <!-- color picker -->
<input type="range" min="0" max="100" step="5"> <!-- slider -->
<input type="file" accept=".jpg,.png" multiple>  <!-- file upload -->
<input type="search">      <!-- search keyboard, clear button on some browsers -->
<input type="checkbox">   <!-- boolean value -->
<input type="radio">       <!-- one-of-many -->
```

### JavaScript Validation

```javascript
const form = document.getElementById('registration');

const validators = {
  email: (value) => {
    if (!value) return 'Email is required';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) return 'Enter a valid email address';
    return null;
  },
  password: (value) => {
    if (!value) return 'Password is required';
    if (value.length < 8) return 'Password must be at least 8 characters';
    if (!/[A-Z]/.test(value)) return 'Password must contain one uppercase letter';
    if (!/[0-9]/.test(value)) return 'Password must contain one number';
    return null;
  }
};

function showError(fieldName, message) {
  const field = form.querySelector(`[name="${fieldName}"]`);
  const errorEl = document.getElementById(`${fieldName}-error`);
  if (message) {
    field.setAttribute('aria-invalid', 'true');
    errorEl.textContent = message;
    errorEl.removeAttribute('hidden');
  } else {
    field.removeAttribute('aria-invalid');
    errorEl.hidden = true;
  }
}

form.addEventListener('submit', async (e) => {
  e.preventDefault();
  const formData = new FormData(form);
  let hasErrors = false;

  for (const [field, validator] of Object.entries(validators)) {
    const error = validator(formData.get(field));
    showError(field, error);
    if (error) {
      hasErrors = true;
      if (!firstError) form.querySelector(`[name="${field}"]`).focus(); // focus first error
    }
  }

  if (!hasErrors) {
    await submitForm(Object.fromEntries(formData));
  }
});
```

