### Keyboard Navigation

```javascript
// Focus management for modal
function openModal(modal) {
  const focusableSelectors = [
    'button:not([disabled])',
    'input:not([disabled])',
    'a[href]',
    '[tabindex]:not([tabindex="-1"])'
  ].join(', ');

  const focusableElements = modal.querySelectorAll(focusableSelectors);
  const firstFocusable = focusableElements[0];
  const lastFocusable = focusableElements[focusableElements.length - 1];

  modal.hidden = false;
  firstFocusable.focus(); // move focus into modal

  // Trap focus inside modal
  modal.addEventListener('keydown', function trapFocus(e) {
    if (e.key !== 'Tab') return;
    if (e.shiftKey) {
      if (document.activeElement === firstFocusable) {
        e.preventDefault();
        lastFocusable.focus();
      }
    } else {
      if (document.activeElement === lastFocusable) {
        e.preventDefault();
        firstFocusable.focus();
      }
    }
  });

  modal.addEventListener('keydown', function closeOnEsc(e) {
    if (e.key === 'Escape') closeModal(modal, triggerElement);
  });
}

function closeModal(modal, trigger) {
  modal.hidden = true;
  trigger.focus(); // return focus to the element that opened the modal
}
